"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[95026],{32427(e,t,s){s.r(t),s.d(t,{assets:()=>c,contentTitle:()=>a,default:()=>f,frontMatter:()=>r,metadata:()=>o,toc:()=>d});let o=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 Revenue from Contracts with Customers/assessment-of-promised-goods-or-serv-0eae0a67ed","title":"Assessment of promised goods or services (IFRS 15)","description":"January 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 Revenue from Contracts with Customers/Assessment of promised goods or services (IFRS 15).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 Revenue from Contracts with Customers","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/assessment-of-promised-goods-or-serv-0eae0a67ed","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/assessment-of-promised-goods-or-serv-0eae0a67ed","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"assessment-of-promised-goods-or-serv-0eae0a67ed","title":"Assessment of promised goods or services (IFRS 15)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/assessment-of-promised-goods-or-serv-0eae0a67ed","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Sale of Output by a Joint Operator (IFRS 11)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-11-joint-arrangements-5488ddb2b3/sale-of-output-by-a-joint-operator-i-522dbe0f6f"},"next":{"title":"Compensation for Delays or Cancellations (IFRS 15)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/compensation-for-delays-or-cancellat-140b02cec9"}}');var n=s(74848),i=s(28453);let r={id:"assessment-of-promised-goods-or-serv-0eae0a67ed",title:"Assessment of promised goods or services (IFRS 15)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/assessment-of-promised-goods-or-serv-0eae0a67ed",sidebar_position:1},a="Assessment of promised goods or services (IFRS 15)",c={},d=[{value:"Application of IFRS 15 to the fact pattern in the request",id:"application-of-ifrs-15-to-the-fact-pattern-in-the-request",level:2}];function h(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,i.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"assessment-of-promised-goods-or-services-ifrs-15",children:"Assessment of promised goods or services (IFRS 15)"})}),"\n",(0,n.jsx)(t.p,{children:"January 2019"}),"\n",(0,n.jsx)(t.p,{children:"The Committee received a request about the recognition of revenue by a stock exchange that provides a listing service to a customer. Specifically, the request asked whether the stock exchange promises to transfer an admission service that is distinct from the listing service. In the fact pattern described in the request, the stock exchange charges the customer a non-refundable upfront fee on initial listing and an ongoing listing fee. The upfront fee relates to activities the stock exchange undertakes at or near contract inception."}),"\n",(0,n.jsx)(t.p,{children:"Paragraph 22 of IFRS 15 requires an entity to assess the goods or services promised in a contract with a customer and to identify performance obligations. A performance obligation is a promise to transfer to the customer either:"}),"\n",(0,n.jsx)(t.p,{children:"a. a good or service (or a bundle of goods or services) that is distinct; or\nb. a series of distinct goods or services that are substantially the same and that have the same pattern of transfer to the customer."}),"\n",(0,n.jsx)(t.p,{children:"In paragraph BC87 of IFRS 15, the Board noted that before an entity can identify its performance obligations in a contract with a customer, the entity would first need to identify all the promised goods or services in that contract."}),"\n",(0,n.jsx)(t.p,{children:"Paragraph 25 of IFRS 15 specifies that performance obligations do not include activities that an entity must undertake to fulfil a contract unless those activities transfer a good or service to a customer."}),"\n",(0,n.jsx)(t.p,{children:"Paragraph B49 of IFRS 15 states that to identify performance obligations in contracts in which an entity charges a non-refundable upfront fee, the entity assesses whether the fee relates to the transfer of a promised good or service. In many cases, even though a non-refundable upfront fee relates to an activity that the entity is required to undertake at or near contract inception to fulfil the contract, that activity does not result in the transfer\nof a promised good or service to the customer."}),"\n",(0,n.jsx)(t.p,{children:"Accordingly, the Committee noted that when an entity charges a customer a non-refundable upfront fee, the entity considers whether it transfers a promised good or service to the customer at or near contract inception or, instead, for example, whether any activities it performs at or near contract inception represent tasks to set up a contract."}),"\n",(0,n.jsx)(t.h2,{id:"application-of-ifrs-15-to-the-fact-pattern-in-the-request",children:"Application of IFRS 15 to the fact pattern in the request"}),"\n",(0,n.jsx)(t.p,{children:"The assessment of the goods and services promised in a contract and the identification of performance obligations requires an assessment of the facts and circumstances of the contract. Accordingly, the outcome of an entity\u2019s assessment depends on those facts and circumstances."}),"\n",(0,n.jsx)(t.p,{children:"In the fact pattern described in the request, the stock exchange charges the customer a non-refundable upfront fee and an ongoing listing fee. The stock exchange undertakes various activities at or near contract inception to enable admission to the exchange, such as:\n\u2022 performing due diligence for new applications;"}),"\n",(0,n.jsx)(t.p,{children:"\u2022 reviewing the customer\u2019s listing application (including assessing whether to accept\nthe application);\n\u2022 issuing reference numbers and tickers for the new security;\n\u2022 processing the listing and admission to the market;\n\u2022 publishing the security on the order book; and\n\u2022 issuing the dealing notice on the admission date."}),"\n",(0,n.jsx)(t.p,{children:"The Committee observed that the activities performed by the entity at or near contract inception are required to transfer the goods or services for which the customer has contracted\u2014ie the service of being listed on the exchange. However, the entity\u2019s performance of those activities does not transfer a service to the customer."}),"\n",(0,n.jsx)(t.p,{children:"The Committee also observed that the listing service transferred to the customer is the same on initial listing and on all subsequent days for which the customer remains listed."}),"\n",(0,n.jsx)(t.p,{children:"Based on the fact pattern described in the request, the Committee concluded that the stock exchange does not promise to transfer any good or service to the customer other than the service of being listed on the exchange."}),"\n",(0,n.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS 15 provide an adequate basis for an entity to assess the promised goods and services in a contract with a customer. Consequently, the Committee decided not to add this matter to its standard-setting agenda."})]})}function f(e={}){let{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(h,{...e})}):h(e)}},28453(e,t,s){s.d(t,{R:()=>r,x:()=>a});var o=s(96540);let n={},i=o.createContext(n);function r(e){let t=o.useContext(i);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:r(e.components),o.createElement(i.Provider,{value:t},e.children)}}}]);